    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> SideBandSealing {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .fresh
        
        case 2: return .stable
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: SideBandSealing, into buf: inout [UInt8]) {
        switch value {
        
        
        case .fresh:
            writeInt(&buf, Int32(1))
        
        
        case .stable:
            writeInt(&buf, Int32(2))
        
        }
    }
}


