fileprivate struct FfiConverterSequenceTypeEpochRendezvous: FfiConverterRustBuffer {
    typealias SwiftType = [EpochRendezvous]

    public static func write(_ value: [EpochRendezvous], into buf: inout [UInt8]) {
        let len = Int32(value.count)
        writeInt(&buf, len)
        for item in value {
            FfiConverterTypeEpochRendezvous.write(item, into: &buf)
        }
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> [EpochRendezvous] {
        let len: Int32 = try readInt(&buf)
        var seq = [EpochRendezvous]()
        seq.reserveCapacity(Int(len))
        for _ in 0 ..< len {
            seq.append(try FfiConverterTypeEpochRendezvous.read(from: &buf))
        }
        return seq
    }
}
